{"path": "/tmp/sv-cef740efacdf41d1892e1b35fc5d1f2a/SiteInspector/src/SiteInspector.Client/Services/InspectionStore.cs", "file_text": "using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Offline-first data store backed by IndexedDB via JS interop.
/// All reads/writes go to IndexedDB so the app works without a network connection.
/// </summary>
public sealed class InspectionStore
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public InspectionStore(IJSRuntime js) => _js = js;

    // --- Sites ---

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "sites");
        return Deserialize<List<ConstructionSite>>(items);
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "sites", id);
        return item.HasValue ? Deserialize<ConstructionSite>(item.Value) : null;
    }

    public async Task SaveSiteAsync(ConstructionSite site) =>
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "sites", site);

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "sites", id);

    // --- Reports ---

    public async Task<List<InspectionReport>> GetReportsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "reports");
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task<InspectionReport?> GetReportAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "reports", id);
        return item.HasValue ? Deserialize<InspectionReport>(item.Value) : null;
    }

    public async Task<List<InspectionReport>> GetReportsForSiteAsync(string siteId)
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "reports", "siteId", siteId);
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task<List<InspectionReport>> GetPendingReportsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "reports", "syncStatus", (int)SyncStatus.Pending);
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task SaveReportAsync(InspectionReport report) =>
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "reports", report);

    public async Task DeleteReportAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "reports", id);

    private static T Deserialize<T>(JsonElement element) =>
        JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions)!;
}
"}

{"path": "/tmp/sv-cef740efacdf41d1892e1b35fc5d1f2a/SiteInspector/src/SiteInspector.Client/Services/ConnectivityService.cs", "file_text": "using Microsoft.JSInterop;

namespace SiteInspector.Client.Services;

/// <summary>
/// Tracks browser online/offline state and raises events on change.
/// </summary>
public sealed class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;
    private bool _isOnline;
    private bool _initialized;

    public event Func<bool, Task>? ConnectivityChanged;

    public bool IsOnline => _isOnline;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        if (_initialized) return;
        _initialized = true;

        _isOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        _isOnline = isOnline;
        if (ConnectivityChanged is not null)
            await ConnectivityChanged.Invoke(isOnline);
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}
"}

{"path": "/tmp/sv-cef740efacdf41d1892e1b35fc5d1f2a/SiteInspector/src/SiteInspector.Client/Services/SyncService.cs", "file_text": "using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Background sync: pushes locally-saved inspection reports to the server API
/// when connectivity is available. Runs on a timer and also triggers on
/// connectivity-restored events.
/// </summary>
public sealed class SyncService : IAsyncDisposable
{
    private readonly InspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private readonly ILogger<SyncService> _logger;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private bool _syncing;

    public int PendingCount { get; private set; }
    public DateTime? LastSyncAttempt { get; private set; }
    public event Action? SyncStateChanged;

    public SyncService(
        InspectionStore store,
        ConnectivityService connectivity,
        HttpClient http,
        ILogger<SyncService> logger)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
        _logger = logger;
    }

    public async Task StartAsync()
    {
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
        await RefreshPendingCount();

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromMinutes(2));
        _ = RunTimerLoop(_cts.Token);
    }

    private async Task RunTimerLoop(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await TrySyncAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await TrySyncAsync();
    }

    public async Task TrySyncAsync()
    {
        if (_syncing || !_connectivity.IsOnline) return;

        _syncing = true;
        LastSyncAttempt = DateTime.UtcNow;

        try
        {
            var pending = await _store.GetPendingReportsAsync();
            foreach (var report in pending)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", report);
                    if (response.IsSuccessStatusCode)
                    {
                        report.SyncStatus = SyncStatus.Synced;
                        await _store.SaveReportAsync(report);
                    }
                    else
                    {
                        _logger.LogWarning("Sync failed for report {Id}: {Status}", report.Id, response.StatusCode);
                    }
                }
                catch (Exception ex)
                {
                    _logger.LogWarning(ex, "Sync error for report {Id}", report.Id);
                    report.SyncStatus = SyncStatus.Error;
                    await _store.SaveReportAsync(report);
                }
            }
        }
        finally
        {
            _syncing = false;
            await RefreshPendingCount();
            SyncStateChanged?.Invoke();
        }
    }

    private async Task RefreshPendingCount()
    {
        try
        {
            var pending = await _store.GetPendingReportsAsync();
            PendingCount = pending.Count;
        }
        catch
        {
            PendingCount = 0;
        }
    }

    public async ValueTask DisposeAsync()
    {
        _connectivity.ConnectivityChanged -= OnConnectivityChanged;
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        await ValueTask.CompletedTask;
    }
}
"}

