using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Offline-first data store backed by IndexedDB via JS interop.
/// All reads/writes go to IndexedDB so the app works without a network connection.
/// </summary>
public sealed class InspectionStore
{
    private readonly IJSRuntime _js;
    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        PropertyNameCaseInsensitive = true
    };

    public InspectionStore(IJSRuntime js) => _js = js;

    // --- Sites ---

    public async Task<List<ConstructionSite>> GetSitesAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "sites");
        return Deserialize<List<ConstructionSite>>(items);
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "sites", id);
        return item.HasValue ? Deserialize<ConstructionSite>(item.Value) : null;
    }

    public async Task SaveSiteAsync(ConstructionSite site) =>
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "sites", site);

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "sites", id);

    // --- Reports ---

    public async Task<List<InspectionReport>> GetReportsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "reports");
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task<InspectionReport?> GetReportAsync(string id)
    {
        var item = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "reports", id);
        return item.HasValue ? Deserialize<InspectionReport>(item.Value) : null;
    }

    public async Task<List<InspectionReport>> GetReportsForSiteAsync(string siteId)
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "reports", "siteId", siteId);
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task<List<InspectionReport>> GetPendingReportsAsync()
    {
        var items = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getItemsByIndex", "reports", "syncStatus", (int)SyncStatus.Pending);
        return Deserialize<List<InspectionReport>>(items);
    }

    public async Task SaveReportAsync(InspectionReport report) =>
        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "reports", report);

    public async Task DeleteReportAsync(string id) =>
        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "reports", id);

    private static T Deserialize<T>(JsonElement element) =>
        JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions)!;
}

