using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Background sync: pushes locally-saved inspection reports to the server API
/// when connectivity is available. Runs on a timer and also triggers on
/// connectivity-restored events.
/// </summary>
public sealed class SyncService : IAsyncDisposable
{
    private readonly InspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private readonly ILogger<SyncService> _logger;
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private bool _syncing;

    public int PendingCount { get; private set; }
    public DateTime? LastSyncAttempt { get; private set; }
    public event Action? SyncStateChanged;

    public SyncService(
        InspectionStore store,
        ConnectivityService connectivity,
        HttpClient http,
        ILogger<SyncService> logger)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
        _logger = logger;
    }

    public async Task StartAsync()
    {
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
        await RefreshPendingCount();

        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromMinutes(2));
        _ = RunTimerLoop(_cts.Token);
    }

    private async Task RunTimerLoop(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await TrySyncAsync();
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await TrySyncAsync();
    }

    public async Task TrySyncAsync()
    {
        if (_syncing || !_connectivity.IsOnline) return;

        _syncing = true;
        LastSyncAttempt = DateTime.UtcNow;

        try
        {
            var pending = await _store.GetPendingReportsAsync();
            foreach (var report in pending)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("api/inspections/sync", report);
                    if (response.IsSuccessStatusCode)
                    {
                        report.SyncStatus = SyncStatus.Synced;
                        await _store.SaveReportAsync(report);
                    }
                    else
                    {
                        _logger.LogWarning("Sync failed for report {Id}: {Status}", report.Id, response.StatusCode);
                    }
                }
                catch (Exception ex)
                {
                    _logger.LogWarning(ex, "Sync error for report {Id}", report.Id);
                    report.SyncStatus = SyncStatus.Error;
                    await _store.SaveReportAsync(report);
                }
            }
        }
        finally
        {
            _syncing = false;
            await RefreshPendingCount();
            SyncStateChanged?.Invoke();
        }
    }

    private async Task RefreshPendingCount()
    {
        try
        {
            var pending = await _store.GetPendingReportsAsync();
            PendingCount = pending.Count;
        }
        catch
        {
            PendingCount = 0;
        }
    }

    public async ValueTask DisposeAsync()
    {
        _connectivity.ConnectivityChanged -= OnConnectivityChanged;
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
        await ValueTask.CompletedTask;
    }
}

