@page "/"

@inject InspectionStore Store
@inject NavigationManager Nav

<div class="page-content">
    <div class="text-center mb-4">
        <h4 class="fw-bold">Safety Inspection</h4>
        <p class="text-muted mb-3">Select a site to begin inspection</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-success" role="status"></div>
        </div>
    }
    else
    {
        @if (_sites.Any())
        {
            <div class="list-group mb-4">
                @foreach (var site in _sites)
                {
                    <button class="list-group-item list-group-item-action d-flex justify-content-between align-items-center site-card"
                            @onclick="() => StartInspection(site)">
                        <div>
                            <div class="fw-semibold">@site.Name</div>
                            <small class="text-muted">@site.Address</small>
                        </div>
                        <span class="badge bg-success rounded-pill">Start →</span>
                    </button>
                }
            </div>
        }
        else
        {
            <div class="alert alert-info">
                No construction sites yet.
                <a href="/sites" class="alert-link">Add a site</a> to get started.
            </div>
        }

        @if (_recentReports.Any())
        {
            <h6 class="fw-bold text-muted mb-2">Recent Inspections</h6>
            <div class="list-group">
                @foreach (var report in _recentReports)
                {
                    <a href="/report/@report.Id" class="list-group-item list-group-item-action">
                        <div class="d-flex justify-content-between">
                            <span class="fw-semibold">@report.SiteName</span>
                            <SyncIcon Status="report.SyncStatus" />
                        </div>
                        <small class="text-muted">
                            @report.InspectorName — @report.CreatedAt.ToLocalTime().ToString("MMM dd, h:mm tt")
                        </small>
                        <div class="mt-1">
                            @{ var total = report.ChecklistItems.Count; var done = report.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked); }
                            <div class="progress" style="height: 6px;">
                                <div class="progress-bar bg-success" style="width: @(total > 0 ? done * 100 / total : 0)%"></div>
                            </div>
                        </div>
                    </a>
                }
            </div>
        }
    }
</div>

@code {
    private List<ConstructionSite> _sites = new();
    private List<InspectionReport> _recentReports = new();
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Store.GetSitesAsync();
        _recentReports = (await Store.GetReportsAsync())
            .OrderByDescending(r => r.CreatedAt)
            .Take(10)
            .ToList();
        _loading = false;
    }

    private void StartInspection(ConstructionSite site)
    {
        Nav.NavigateTo($"/inspect/{site.Id}");
    }
}

