            <div class="col-3">
                <div class="summary-card text-center">
                    <div class="fs-4 fw-bold text-secondary">@na</div>
                    <small>N/A</small>
                </div>
            </div>
            <div class="col-3">
                <div class="summary-card text-center">
                    <div class="fs-4 fw-bold text-warning">@unchecked_</div>
                    <small>Skipped</small>
                </div>
            </div>
