@inject InspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-content">
    @if (_report is null)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-success" role="status"></div>
        </div>
    }
    else
    {
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <h5 class="fw-bold mb-0">@_report.SiteName</h5>
                <small class="text-muted">@_report.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</small>
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-outline-secondary btn-sm" @onclick="SaveAndExit">💾 Save</button>
                <button class="btn btn-success btn-sm" @onclick="CompleteInspection">✅ Complete</button>
            </div>
        </div>

        @if (!_inspectorSet)
        {
            <div class="card mb-3">
                <div class="card-body">
                    <label class="form-label fw-semibold">Inspector Name</label>
                    <div class="d-flex gap-2">
                        <input type="text" class="form-control" placeholder="Your name"
                               @bind="_inspectorName" @bind:event="oninput" />
                        <button class="btn btn-success" @onclick="SetInspector"
                                disabled="@string.IsNullOrWhiteSpace(_inspectorName)">Go</button>
                    </div>
                </div>
            </div>
        }
        else
        {
            <!-- Progress bar -->
            @{
                var total = _report.ChecklistItems.Count;
                var done = _report.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
                var pct = total > 0 ? done * 100 / total : 0;
            }
            <div class="mb-3">
                <div class="d-flex justify-content-between mb-1">
                    <small class="text-muted">Progress</small>
                    <small class="fw-bold">@done / @total</small>
                </div>
                <div class="progress" style="height: 8px;">
                    <div class="progress-bar bg-success" style="width: @pct%"></div>
                </div>
            </div>

            <!-- Category tabs -->
            <div class="category-tabs mb-3">
                @foreach (var cat in _categories)
                {
                    var catItems = _report.ChecklistItems.Where(c => c.Category == cat).ToList();
                    var catDone = catItems.Count(c => c.Result != CheckResult.NotChecked);
                    var isActive = _activeCategory == cat;
                    <button class="category-tab @(isActive ? "active" : "") @(catDone == catItems.Count ? "complete" : "")"
                            @onclick="() => _activeCategory = cat">
                        @cat
                        <span class="cat-count">@catDone/@catItems.Count</span>
                    </button>
                }
            </div>

            <!-- Checklist items for active category -->
            <div class="checklist-items">
                @foreach (var item in _report.ChecklistItems.Where(c => c.Category == _activeCategory))
                {
                    <div class="checklist-item @GetItemClass(item)">
                        <div class="d-flex justify-content-between align-items-start">
                            <span class="checklist-desc">@item.Description</span>
                        </div>
                        <div class="checklist-actions mt-2">
                            <button class="btn-check-result @(item.Result == CheckResult.Pass ? "active-pass" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
                            <button class="btn-check-result @(item.Result == CheckResult.Fail ? "active-fail" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
                            <button class="btn-check-result @(item.Result == CheckResult.NA ? "active-na" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NA)">N/A</button>
                        </div>
                        @if (item.Result == CheckResult.Fail || !string.IsNullOrEmpty(item.Notes))
                        {
                            <textarea class="form-control mt-2 checklist-notes"
                                      placeholder="@(item.Result == CheckResult.Fail ? "Describe the issue (required for failures)..." : "Optional notes...")"
                                      rows="2"
                                      @bind="item.Notes"
                                      @bind:event="oninput"></textarea>
                        }
                    </div>
                }
            </div>

            <!-- Notes section -->
            <div class="mt-3">
                <h6 class="fw-bold">General Notes</h6>
                <textarea class="form-control" rows="3" placeholder="Overall site observations..."
                          @bind="_report.Notes" @bind:event="oninput"></textarea>
            </div>

            <!-- Photos section -->
            <div class="mt-3">
                <div class="d-flex justify-content-between align-items-center mb-2">
                    <h6 class="fw-bold mb-0">Photos (@_report.Photos.Count)</h6>
                    <label class="btn btn-outline-success btn-sm mb-0">
                        📷 Add Photo
                        <input type="file" accept="image/*" capture="environment"
                               @ref="_fileInput" @onchange="OnPhotoSelected" hidden />
                    </label>
                </div>

                @if (_report.Photos.Any())
                {
                    <div class="photo-grid">
                        @foreach (var photo in _report.Photos)
                        {
                            <div class="photo-card">
                                <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                                <div class="photo-overlay">
                                    <input type="text" class="form-control form-control-sm"
                                           placeholder="Caption..."
                                           @bind="photo.Caption" @bind:event="oninput" />
                                    <button class="btn btn-sm btn-outline-danger mt-1"
                                            @onclick="() => RemovePhoto(photo)">Remove</button>
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>
        }
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private InspectionReport? _report;
    private List<string> _categories = new();
    private string _activeCategory = "";
    private string _inspectorName = "";
    private bool _inspectorSet;
    private ElementReference _fileInput;

    protected override async Task OnInitializedAsync()
    {
        var site = await Store.GetSiteAsync(SiteId);
        if (site is null)
        {
            Nav.NavigateTo("/");
            return;
        }

        _report = new InspectionReport
        {
            SiteId = site.Id,
            SiteName = site.Name,
            ChecklistItems = ChecklistTemplates.GetStandardChecklist()
        };

        _categories = _report.ChecklistItems.Select(c => c.Category).Distinct().ToList();
        _activeCategory = _categories.First();
    }

    private void SetInspector()
    {
        _report!.InspectorName = _inspectorName.Trim();
        _inspectorSet = true;
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        // Auto-save on each tap for offline resilience
        await Store.SaveReportAsync(_report!);
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NA => "item-na",
        _ => ""
    };

    private async Task OnPhotoSelected()
    {
        var result = await JS.InvokeAsync<PhotoResult?>("fileInterop.readFileAsBase64", _fileInput);
        if (result is not null)
        {
            _report!.Photos.Add(new InspectionPhoto
            {
                FileName = result.FileName,
                Base64Data = result.Base64Data
            });
            await Store.SaveReportAsync(_report);
        }
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _report!.Photos.Remove(photo);
        await Store.SaveReportAsync(_report);
    }

    private async Task SaveAndExit()
    {
        if (_report is not null)
        {
            await Store.SaveReportAsync(_report);
        }
        Nav.NavigateTo("/");
    }

    private async Task CompleteInspection()
    {
        if (_report is not null)
        {
            _report.CompletedAt = DateTime.UtcNow;
            _report.SyncStatus = SyncStatus.Pending;
            await Store.SaveReportAsync(_report);
        }
        Nav.NavigateTo($"/report/{_report!.Id}");
    }

    private record PhotoResult(string FileName, string Base64Data);
}
