            var fail = _report.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
            var na = _report.ChecklistItems.Count(c => c.Result == CheckResult.NA);
            var unchecked_ = _report.ChecklistItems.Count(c => c.Result == CheckResult.NotChecked);
        }
        <div class="row g-2 mb-3">
            <div class="col-3">
                <div class="summary-card text-center">
                    <div class="fs-4 fw-bold text-success">@pass</div>
