@inject ConnectivityService Connectivity
@inject SyncService Sync
@implements IDisposable

<div class="sync-badge @(_isOnline ? "online" : "offline")" @onclick="OnSyncClick">
    @if (_isOnline)
    {
        <span>✅ Online</span>
    }
    else
    {
        <span>📴 Offline</span>
    }
    @if (_pendingCount > 0)
    {
        <span class="badge bg-warning text-dark ms-1">@_pendingCount</span>
    }
</div>

@code {
    private bool _isOnline;
    private int _pendingCount;

    protected override async Task OnInitializedAsync()
    {
        await Connectivity.InitializeAsync();
        _isOnline = Connectivity.IsOnline;
        Connectivity.ConnectivityChanged += OnConnectivityChanged;
        Sync.SyncStateChanged += OnSyncStateChanged;
        await Sync.StartAsync();
        _pendingCount = Sync.PendingCount;
    }

    private async Task OnConnectivityChanged(bool isOnline)
    {
        _isOnline = isOnline;
        await InvokeAsync(StateHasChanged);
    }

    private void OnSyncStateChanged()
    {
        _pendingCount = Sync.PendingCount;
        InvokeAsync(StateHasChanged);
    }

    private async Task OnSyncClick()
    {
        if (_isOnline)
            await Sync.TrySyncAsync();
    }

    public void Dispose()
    {
        Connectivity.ConnectivityChanged -= OnConnectivityChanged;
        Sync.SyncStateChanged -= OnSyncStateChanged;
    }
}

