@inject InspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-content">
    @if (_report is null)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-success" role="status"></div>
        </div>
    }
    else
    {
        <div class="d-flex justify-content-between align-items-center mb-3">
            <div>
                <h5 class="fw-bold mb-0">@_report.SiteName</h5>
                <small class="text-muted">@_report.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")</small>
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-outline-secondary btn-sm" @onclick="SaveAndExit">💾 Save</button>
                <button class="btn btn-success btn-sm" @onclick="CompleteInspection">✅ Complete</button>
            </div>
        </div>

        @if (!_inspectorSet)
        {
            <div class="card mb-3">
                <div class="card-body">
                    <label class="form-label fw-semibold">Inspector Name</label>
