arguments.new_str:
/* ===== Mobile-first App Shell ===== */
html, body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    margin: 0;
    padding: 0;
    background: #f0f4f0;
    -webkit-tap-highlight-color: transparent;
    overscroll-behavior: none;
}

.app-container {
    display: flex;
    flex-direction: column;
    min-height: 100dvh;
}

.app-header {
    background: #1a5632;
    color: white;
    position: sticky;
    top: 0;
    z-index: 100;
    box-shadow: 0 2px 4px rgba(0,0,0,.15);
}

.app-content {
    flex: 1;
    overflow-y: auto;
    padding-bottom: 70px; /* space for bottom nav */
}

.app-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: white;
    border-top: 1px solid #dee2e6;
    display: flex;
    justify-content: space-around;
    z-index: 100;
    padding-bottom: env(safe-area-inset-bottom);
}

.nav-tab {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 8px 16px;
    color: #6c757d;
    text-decoration: none;
    font-size: 0.75rem;
    transition: color 0.15s;
}

.nav-tab .nav-icon {
    font-size: 1.3rem;
    line-height: 1;
}

.nav-tab.active {
    color: #1a5632;
    font-weight: 600;
}

.page-content {
    padding: 16px;
    max-width: 600px;
    margin: 0 auto;
    width: 100%;
}

/* ===== Sync Badge ===== */
.sync-badge {
    display: flex;
    align-items: center;
    font-size: 0.8rem;
    padding: 4px 10px;
    border-radius: 20px;
    cursor: pointer;
    user-select: none;
}

.sync-badge.online {
    background: rgba(255,255,255,.2);
}

.sync-badge.offline {
    background: rgba(255,100,100,.3);
}

/* ===== Site Cards ===== */
.site-card {
    border-left: 4px solid #1a5632;
    transition: background 0.1s;
}

.site-card:active {
    background: #e8f5e9 !important;
}

/* ===== Checklist ===== */
.category-tabs {
    display: flex;
    gap: 6px;
    overflow-x: auto;
    padding-bottom: 4px;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
}

.category-tabs::-webkit-scrollbar {
    display: none;
}

.category-tab {
    flex-shrink: 0;
    padding: 6px 12px;
    border: 1px solid #dee2e6;
    border-radius: 20px;
    background: white;
    font-size: 0.8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 4px;
    transition: all 0.15s;
}

.category-tab.active {
    background: #1a5632;
    color: white;
    border-color: #1a5632;
}

.category-tab.complete {
    border-color: #198754;
}

.cat-count {
    font-size: 0.7rem;
    opacity: 0.7;
}

.checklist-item {
    background: white;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 12px;
    margin-bottom: 8px;
    transition: border-color 0.15s;
}

.checklist-item.item-pass {
    border-left: 4px solid #198754;
    background: #f8fdf9;
}

.checklist-item.item-fail {
    border-left: 4px solid #dc3545;
    background: #fef8f8;
}

.checklist-item.item-na {
    border-left: 4px solid #6c757d;
    background: #fafafa;
}

.checklist-desc {
    font-size: 0.9rem;
    line-height: 1.3;
}

.checklist-actions {
    display: flex;
    gap: 8px;
}

.btn-check-result {
    flex: 1;
    padding: 8px 4px;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    background: white;
    font-size: 0.85rem;
    cursor: pointer;
    transition: all 0.1s;
    -webkit-tap-highlight-color: transparent;
    touch-action: manipulation;
}

.btn-check-result:active {
    transform: scale(0.95);
}

.btn-check-result.active-pass {
    background: #198754;
    color: white;
    border-color: #198754;
}

.btn-check-result.active-fail {
    background: #dc3545;
    color: white;
    border-color: #dc3545;
}

.btn-check-result.active-na {
    background: #6c757d;
    color: white;
    border-color: #6c757d;
}

.checklist-notes {
    font-size: 0.85rem;
    border-radius: 6px;
}

/* ===== Photos ===== */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
    gap: 8px;
}

.photo-card {
    position: relative;
    border-radius: 8px;
    overflow: hidden;
    background: #eee;
}

.photo-card img {
    width: 100%;
    aspect-ratio: 1;
    object-fit: cover;
    display: block;
}

.photo-overlay {
    padding: 6px;
    background: white;
}

.photo-caption {
    padding: 4px 8px;
    background: rgba(0,0,0,.6);
    color: white;
    font-size: 0.75rem;
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
}

/* ===== Report Summary ===== */
.summary-card {
    background: white;
    border-radius: 8px;
    padding: 12px 8px;
    border: 1px solid #dee2e6;
}

/* ===== Loading ===== */
.loading-progress {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 80px;
    height: 80px;
}

.loading-progress circle {
    fill: none;
    stroke: #1a5632;
    stroke-width: 3px;
}

.loading-progress circle:last-child {
    stroke: #d3d3d3;
    stroke-dasharray: calc(3.14 * 80px);
    stroke-dashoffset: calc(3.14 * 80px);
    animation: loading-progress-dash 1.5s ease-in-out infinite;
}

@keyframes loading-progress-dash {
    0% { stroke-dashoffset: calc(3.14 * 80px); }
    50% { stroke-dashoffset: 0; }
    100% { stroke-dashoffset: calc(-3.14 * 80px); }
}

/* ===== Error UI ===== */
#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}

