using System.Collections.Concurrent;
using System.Text.Json;
using System.Text.Json.Serialization;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddCors(options =>
{
    options.AddDefaultPolicy(policy =>
        policy.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader());
});

var app = builder.Build();

app.UseCors();

// In-memory store for synced reports (swap for a real database in production)
var syncedReports = new ConcurrentDictionary<string, JsonElement>();

app.MapPost("/api/inspections/sync", async (HttpRequest request) =>
{
    var body = await JsonSerializer.DeserializeAsync<JsonElement>(request.Body);
    var id = body.GetProperty("id").GetString()!;
    syncedReports[id] = body;
    return Results.Ok(new { id, status = "synced" });
});

app.MapGet("/api/inspections", () =>
{
    return Results.Ok(syncedReports.Values);
});

app.MapGet("/api/inspections/{id}", (string id) =>
{
    return syncedReports.TryGetValue(id, out var report)
        ? Results.Ok(report)
        : Results.NotFound();
});

app.Run();

