    font-size: 0.75rem;
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
}

/* ===== Report Summary ===== */
.summary-card {
    background: white;
    border-radius: 8px;
    padding: 12px 8px;
    border: 1px solid #dee2e6;
}

/* ===== Loading ===== */
.loading-progress {
    position: fixed;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 80px;
    height: 80px;
}

.loading-progress circle {
    fill: none;
    stroke: #1a5632;
    stroke-width: 3px;
}

.loading-progress circle:last-child {
    stroke: #d3d3d3;
    stroke-dasharray: calc(3.14 * 80px);
    stroke-dashoffset: calc(3.14 * 80px);
    animation: loading-progress-dash 1.5s ease-in-out infinite;
}

@keyframes loading-progress-dash {
    0% { stroke-dashoffset: calc(3.14 * 80px); }
    50% { stroke-dashoffset: 0; }
    100% { stroke-dashoffset: calc(-3.14 * 80px); }
}

/* ===== Blazor Error UI ===== */
.blazor-error-boundary {
    background: #b32121;
    padding: 1rem;
    color: white;
}

.blazor-error-boundary::after {
    content: "An error has occurred."
}

#blazor-error-ui {
    background: lightyellow;
    bottom: 0;
    box-shadow: 0 -1px 2px rgba(0, 0, 0, 0.2);
    display: none;
    left: 0;
    padding: 0.6rem 1.25rem 0.7rem 1.25rem;
    position: fixed;
    width: 100%;
    z-index: 1000;
}

#blazor-error-ui .dismiss {
    cursor: pointer;
    position: absolute;
    right: 0.75rem;
    top: 0.5rem;
}
