70.                     </button>
71.                 }
72.             </div>
73. 
74.             <!-- Checklist items for active category -->
75.             <div class="checklist-items">
76.                 @foreach (var item in _report.ChecklistItems.Where(c => c.Category == _activeCategory))
77.                 {
78.                     <div class="checklist-item @GetItemClass(item)">
79.                         <div class="d-flex justify-content-between align-items-start">
80.                             <span class="checklist-desc">@item.Description</span>
81.                         </div>
82.                         <div class="checklist-actions mt-2">
83.                             <button class="btn-check-result @(item.Result == CheckResult.Pass ? "active-pass" : "")"
84.                                     @onclick="() => SetResult(item, CheckResult.Pass)">✓ Pass</button>
85.                             <button class="btn-check-result @(item.Result == CheckResult.Fail ? "active-fail" : "")"
86.                                     @onclick="() => SetResult(item, CheckResult.Fail)">✗ Fail</button>
