144.     [Parameter] public string SiteId { get; set; } = "";
145. 
146.     private InspectionReport? _report;
147.     private List<string> _categories = new();
148.     private string _activeCategory = "";
149.     private string _inspectorName = "";
150.     private bool _inspectorSet;
151.     private ElementReference _fileInput;
152. 
153.     protected override async Task OnInitializedAsync()
154.     {
155.         var site = await Store.GetSiteAsync(SiteId);
156.         if (site is null)
157.         {
158.             Nav.NavigateTo("/");
159.             return;
160.         }
161. 
162.         _report = new InspectionReport
163.         {
164.             SiteId = site.Id,
165.             SiteName = site.Name,
166.             ChecklistItems = ChecklistTemplates.GetStandardChecklist()
167.         };
168. 
169.         _categories = _report.ChecklistItems.Select(c => c.Category).Distinct().ToList();
170.         _activeCategory = _categories.First();
171.     }
172. 
173.     private void SetInspector()
174.     {
175.         _report!.InspectorName = _inspectorName.Trim();
176.         _inspectorSet = true;
177.     }
178. 
179.     private async Task SetResult(ChecklistItem item, CheckResult result)
180.     {
181.         item.Result = item.Result == result ? CheckResult.NotChecked : result;
182.         // Auto-save on each tap for offline resilience
183.         await Store.SaveReportAsync(_report!);
184.     }
185. 
186.     private string GetItemClass(ChecklistItem item) => item.Result switch
187.     {
188.         CheckResult.Pass => "item-pass",
189.         CheckResult.Fail => "item-fail",
190.         CheckResult.NA => "item-na",
191.         _ => ""
192.     };
193. 
194.     private async Task OnPhotoSelected()
195.     {
196.         var result = await JS.InvokeAsync<PhotoResult?>("fileInterop.readFileAsBase64", _fileInput);
197.         if (result is not null)
198.         {
199.             _report!.Photos.Add(new InspectionPhoto
200.             {
201.                 FileName = result.FileName,
202.                 Base64Data = result.Base64Data
203.             });
204.             await Store.SaveReportAsync(_report);
205.         }
206.     }
207. 
208.     private async Task RemovePhoto(InspectionPhoto photo)
209.     {
210.         _report!.Photos.Remove(photo);
211.         await Store.SaveReportAsync(_report);
212.     }
213. 
214.     private async Task SaveAndExit()
215.     {
216.         if (_report is not null)
217.         {
218.             await Store.SaveReportAsync(_report);
219.         }
220.         Nav.NavigateTo("/");
221.     }
222. 
223.     private async Task CompleteInspection()
224.     {
225.         if (_report is not null)
226.         {
227.             _report.CompletedAt = DateTime.UtcNow;
228.             _report.SyncStatus = SyncStatus.Pending;
229.             await Store.SaveReportAsync(_report);
230.         }
231.         Nav.NavigateTo($"/report/{_report!.Id}");
232.     }
233. 
234.     private record PhotoResult(string FileName, string Base64Data);
235. }
