 @page "/report/{ReportId}"

 @inject InspectionStore Store
 @inject NavigationManager Nav

 <div class="page-content">
     @if (_report is null)
     {
         <div class="text-center py-4">
             <div class="spinner-border text-success" role="status"></div>
         </div>
     }
     else
     {
         <div class="d-flex justify-content-between align-items-center mb-3">
             <div>
                 <h5 class="fw-bold mb-0">@_report.SiteName</h5>
                 <small class="text-muted">
                     @_report.InspectorName — @_report.CreatedAt.ToLocalTime().ToString("MMM dd, yyyy h:mm tt")
                 </small>
             </div>
             <SyncIcon Status="_report.SyncStatus" />
         </div>

         @if (_report.CompletedAt.HasValue)
         {
             <div class="alert alert-success py-2">
                 ✅ Completed @_report.CompletedAt.Value.ToLocalTime().ToString("MMM dd, h:mm tt")
             </div>
         }

         <!-- Summary -->
         @{
             var total = _report.ChecklistItems.Count;
             var pass = _report.ChecklistItems.Count(c => c.Result == CheckResult.Pass);
             var fail = _report.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
             var na = _report.ChecklistItems.Count(c => c.Result == CheckResult.NA);
             var unchecked_ = _report.ChecklistItems.Count(c => c.Result == CheckResult.NotChecked);
         }
         <div class="row g-2 mb-3">
             <div class="col-3">
                 <div class="summary-card text-center">
                     <div class="fs-4 fw-bold text-success">@pass</div>
                     <small>Pass</small>
                 </div>
             </div>
             <div class="col-3">
                 <div class="summary-card text-center">
                     <div class="fs-4 fw-bold text-danger">@fail</div>
                     <small>Fail</small>
                 </div>
             </div>
             <div class="col-3">
                 <div class="summary-card text-center">
                     <div class="fs-4 fw-bold text-secondary">@na</div>
                     <small>N/A</small>
                 </div>
             </div>
             <div class="col-3">
                 <div class="summary-card text-center">
                     <div class="fs-4 fw-bold text-warning">@unchecked_</div>
                     <small>Skipped</small>
                 </div>
             </div>
         </div>

         <!-- Failures -->
         @{
             var failures = _report.ChecklistItems.Where(c => c.Result == CheckResult.Fail).ToList();
         }
         @if (failures.Any())
         {
             <div class="mb-3">
                 <h6 class="fw-bold text-danger">⚠️ Failures (@failures.Count)</h6>
                 <div class="list-group">
                     @foreach (var item in failures)
                     {
                         <div class="list-group-item list-group-item-danger">
                             <div class="fw-semibold">[@item.Category] @item.Description</div>
                             @if (!string.IsNullOrWhiteSpace(item.Notes))
                             {
                                 <small class="d-block mt-1">@item.Notes</small>
                             }
                         </div>
                     }
                 </div>
             </div>
         }

         <!-- Full checklist by category -->
         @foreach (var category in _report.ChecklistItems.Select(c => c.Category).Distinct())
         {
             <div class="mb-3">
                 <h6 class="fw-bold">@category</h6>
                 <div class="list-group">
                     @foreach (var item in _report.ChecklistItems.Where(c => c.Category == category))
                     {
                         <div class="list-group-item py-2 d-flex justify-content-between align-items-center">
                             <span>@item.Description</span>
                             <span class="badge @GetBadgeClass(item.Result)">@item.Result</span>
                         </div>
                     }
                 </div>
             </div>
         }

         <!-- Notes -->
         @if (!string.IsNullOrWhiteSpace(_report.Notes))
         {
             <div class="mb-3">
                 <h6 class="fw-bold">General Notes</h6>
                 <div class="card card-body">@_report.Notes</div>
             </div>
         }

         <!-- Photos -->
         @if (_report.Photos.Any())
         {
             <div class="mb-3">
                 <h6 class="fw-bold">Photos (@_report.Photos.Count)</h6>
                 <div class="photo-grid">
                     @foreach (var photo in _report.Photos)
                     {
                         <div class="photo-card">
                             <img src="data:image/jpeg;base64,@photo.Base64Data" alt="@photo.Caption" />
                             @if (!string.IsNullOrWhiteSpace(photo.Caption))
                             {
                                 <div class="photo-caption">@photo.Caption</div>
                             }
                         </div>
                     }
                 </div>
             </div>
         }

         <div class="d-flex gap-2 mt-3 mb-4">
             <button class="btn btn-outline-danger btn-sm" @onclick="DeleteReport">🗑 Delete</button>
         </div>
     }
 </div>

 @code {
     [Parameter] public string ReportId { get; set; } = "";

     private InspectionReport? _report;

     protected override async Task OnInitializedAsync()
     {
         _report = await Store.GetReportAsync(ReportId);
         if (_report is null)
             Nav.NavigateTo("/");
     }

     private string GetBadgeClass(CheckResult result) => result switch
     {
         CheckResult.Pass => "bg-success",
         CheckResult.Fail => "bg-danger",
         CheckResult.NA => "bg-secondary",
         _ => "bg-warning text-dark"
     };

     private async Task DeleteReport()
     {
         await Store.DeleteReportAsync(ReportId);
         Nav.NavigateTo("/");
     }
 }

